actionCellButton.customFunction:
// f($event, widgetContext, entityId, entityName, additionalParams, entityLabel)

var sc = widgetContext.stateController;

// ชื่อ device
var name = (entityName || '').toString().toLowerCase();

// กำหนด state เริ่มต้น
var stateId = 'default';

// route ตาม keyword ในชื่อ
if (name.includes('gateway')) stateId = 'gateway';
else if (name.includes('sensor')) stateId = 'sensor';
else if (name.includes('pump')) stateId = 'pump';

// ส่ง entityId ไปให้ state ปลายทางใช้เป็น alias
sc.openState(stateId, { entityId: entityId, entityName: entityName }, true);

let $injector = widgetContext.$scope.$injector;
let dialogs = $injector.get(widgetContext.servicesMap.get('dialogs'));
let deviceService = $injector.get(widgetContext.servicesMap.get('deviceService'));

openDeleteEntityDialog();

function openDeleteEntityDialog() {
    let title = 'Delete sensor "' +  entityName + '"';
    let content = 'Are you sure you want to delete the sensor "' +
        entityName + '"?';
    dialogs.confirm(title, content, 'Cancel', 'Delete').subscribe(
        function(result) {
            if (result) {
                deleteEntity();
            }
        }
    );
}

function deleteEntity() {
    deviceService.deleteDevice(entityId.id).subscribe(
        function success() {
            widgetContext.updateAliases();
        },
        function fail() {
            showErrorDialog();
        }
    );
}

function showErrorDialog() {
    let title = 'Error';
    let content = 'An error occurred while deleting the sensor. Please try again.';
    dialogs.alert(title, content, 'CLOSE').subscribe(
        function(result) {}
    );
}

